const W = 612; // letter width
const contentW = W - 120; // usable width
const BLUE = '#26acf7';
const DARK = '#1a1a1a';
const GRAY = '#666666';
const BOTTOM = 720;

let y = 50;

function checkPage(needed) {
  if (y + needed > BOTTOM) { doc.addPage(); y = 50; }
}

function drawText(text, opts = {}) {
  const size = opts.size || 14;
  const color = opts.color || DARK;
  const font = opts.bold ? 'Helvetica-Bold' : 'Helvetica';
  const align = opts.align || 'left';
  doc.font(font).fontSize(size).fillColor(color);
  const h = doc.heightOfString(text, { width: contentW, align });
  checkPage(h + 8);
  doc.text(text, 60, y, { width: contentW, align });
  y += h + (opts.gap || 8);
}

function drawDivider() {
  checkPage(15);
  doc.moveTo(60, y).lineTo(W - 60, y).strokeColor(BLUE).lineWidth(2).stroke();
  y += 15;
}

function labeledBlock(label, content) {
  const font = 'Helvetica-Bold';
  doc.font(font).fontSize(14).fillColor(GRAY);
  const lh = doc.heightOfString(label + ' ', { width: contentW });
  const ch = doc.heightOfString(content, { width: contentW });
  checkPage(lh + ch + 12);
  doc.text(label, 60, y, { width: contentW });
  y += lh + 2;
  doc.font('Helvetica').fontSize(14).fillColor(DARK);
  doc.text(content, 60, y, { width: contentW });
  y += ch + 10;
}

