// ============ RENDER CHAPTERS ============

let currentPart = '';

chapters.forEach(ch => {
  // Part header
  if (ch.part && ch.part !== currentPart) {
    doc.addPage(); y = 50;
    currentPart = ch.part;
    drawText(currentPart, { size: 22, bold: true, color: BLUE, align: 'center', gap: 30 });
    drawDivider();
  }

  // ---- TIKTOK PAGE ----
  doc.addPage(); y = 50;
  drawText(`Chapter ${ch.num}: ${ch.title}`, { size: 20, bold: true, color: BLUE, gap: 6 });
  drawText('TikTok Script (Short Form)', { size: 16, bold: true, color: DARK, gap: 8 });
  drawDivider();

  labeledBlock('HOOK (0-3 sec):', ch.tiktok.hook);
  labeledBlock('SETUP (3-18 sec):', ch.tiktok.setup);
  labeledBlock('CONTENT (18-55 sec):', ch.tiktok.content);
  labeledBlock('CTA (55-end):', ch.tiktok.cta);
  
  drawDivider();
  labeledBlock('Estimated Duration:', ch.tiktok.duration);
  labeledBlock('Hashtags:', ch.tiktok.hashtags);
  labeledBlock('Caption:', ch.tiktok.caption);

  // ---- YOUTUBE PAGE ----
  doc.addPage(); y = 50;
  drawText(`Chapter ${ch.num}: ${ch.title}`, { size: 20, bold: true, color: BLUE, gap: 6 });
  drawText('YouTube Script (Long Form)', { size: 16, bold: true, color: DARK, gap: 8 });
  drawDivider();

  labeledBlock('TITLE:', ch.youtube.title);
  labeledBlock('THUMBNAIL TEXT:', ch.youtube.thumbnail);
  labeledBlock('INTRO/HOOK (0:00-0:30):', ch.youtube.intro);

  drawDivider();
  drawText('Chapter Breakdown', { size: 16, bold: true, color: BLUE, gap: 8 });

  ch.youtube.chapters.forEach(section => {
    checkPage(40);
    drawText(`[${section.ts}] ${section.title}`, { size: 15, bold: true, color: DARK, gap: 4 });
    drawText(section.script, { size: 14, gap: 12 });
  });

  drawDivider();
  labeledBlock('OUTRO:', ch.youtube.outro);
  labeledBlock('Estimated Duration:', ch.youtube.duration);
  labeledBlock('Tags/Keywords:', ch.youtube.tags);
  labeledBlock('Description:', ch.youtube.description);
});

doc.end();
out.on('finish', () => console.log('PDF generated successfully.'));
